/** Indice rapido per id. */
export const menuById: Record<string, Dish> = menu.reduce(
  (acc, d) => {
    acc[d.id] = d;
    return acc;
  },
  {} as Record<string, Dish>,
);

export function getDish(id: string): Dish | undefined {
  return menuById[id];
}

export const featuredDishes: Dish[] = menu.filter((d) => d.isFeatured);
